namespace sv_92f3ccf94134426c8a03cdf569e768a8.Services;

public class WizardState
{
    public int CurrentStep { get; private set; } = 1;
    public const int TotalSteps = 4;
    public HashSet<int> CompletedSteps { get; } = new();

    // Step 1: Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobEntry> JobHistory { get; set; } = new();

    // Step 3: References
    public List<Reference> References { get; set; } = new();

    public event Action? OnChange;

    public void SetCurrentStep(int step)
    {
        CurrentStep = step;
        NotifyStateChanged();
    }

    public void CompleteStep(int step)
    {
        CompletedSteps.Add(step);
        NotifyStateChanged();
    }

    private void NotifyStateChanged() => OnChange?.Invoke();
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class Reference
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

@using sv_92f3ccf94134426c8a03cdf569e768a8.Services
@inject WizardState Wizard
@implements IDisposable

@if (ShowProgressBar)
{
    <div class="wizard-progress d-flex align-items-center gap-2 px-4 py-2">
        <strong>Step @Wizard.CurrentStep of @WizardState.TotalSteps</strong>
        @for (int i = 1; i <= WizardState.TotalSteps; i++)
        {
            var step = i;
            <span class="badge @GetBadgeClass(step)">@step</span>
        }
    </div>
}

@code {
    [Parameter] public string? CurrentUrl { get; set; }

    private bool ShowProgressBar => CurrentUrl?.StartsWith("/apply", StringComparison.OrdinalIgnoreCase) == true;

    private string GetBadgeClass(int step)
    {
        if (step == Wizard.CurrentStep)
            return "bg-primary";
        if (Wizard.CompletedSteps.Contains(step))
            return "bg-success";
        return "bg-secondary";
    }

    protected override void OnInitialized()
    {
        Wizard.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Wizard.OnChange -= StateHasChanged;
    }
}

