@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_92f3ccf94134426c8a03cdf569e768a8.Services
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Personal Info</PageTitle>

<h3>Step 1: Personal Information</h3>

<div class="mb-3">
    <label class="form-label">Name</label>
    <input class="form-control" @bind="Wizard.Name" />
</div>

<div class="mb-3">
    <label class="form-label">Email</label>
    <input class="form-control" type="email" @bind="Wizard.Email" />
</div>

<button class="btn btn-primary" @onclick="Next">Next →</button>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(1);
    }

    private void Next()
    {
        Wizard.CompleteStep(1);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_92f3ccf94134426c8a03cdf569e768a8.Services
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - Experience</PageTitle>

<h3>Step 2: Work Experience</h3>

@for (int i = 0; i < Wizard.JobHistory.Count; i++)
{
    var index = i;
    <div class="card mb-2 p-2">
        <div class="mb-1">
            <input class="form-control" placeholder="Company" @bind="Wizard.JobHistory[index].Company" />
        </div>
        <div class="mb-1">
            <input class="form-control" placeholder="Title" @bind="Wizard.JobHistory[index].Title" />
        </div>
        <div class="mb-1">
            <input class="form-control" placeholder="Years" @bind="Wizard.JobHistory[index].Years" />
        </div>
        <button class="btn btn-sm btn-danger" @onclick="() => Wizard.JobHistory.RemoveAt(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div>
    <button class="btn btn-secondary me-2" @onclick='() => Nav.NavigateTo("/apply/personal-info")'>← Back</button>
    <button class="btn btn-primary" @onclick="Next">Next →</button>
</div>

@code {
    protected override void OnInitialized()
    {
        Wizard.SetCurrentStep(2);
    }

    private void AddJob()
    {
        Wizard.JobHistory.Add(new JobEntry());
    }

    private void Next()
    {
        Wizard.CompleteStep(2);
        Nav.NavigateTo("/apply/references");
    }
}

@page "/apply/references"
@rendermode InteractiveServer
@using sv_92f3ccf94134426c8a03cdf569e768a8.Services
@inject WizardState Wizard
@inject NavigationManager Nav

<PageTitle>Apply - References</PageTitle>

<h3>Step 3: References</h3>

@for (int i = 0; i < Wizard.References.Count; i++)
{
    var index = i;
    <div class="card mb-2 p-2">
        <div class="mb-1">
            <input class="form-control" placeholder="Name" @bind="Wizard.References[index].Name" />
        </div>
        <div class="mb-1">
            <input class="form-control" placeholder="Relationship" @bind="Wizard.References[index].Relationship" />
        </div>
        <div class="mb-1">
            <input class="form-control" placeholder="Phone" @bind="Wizard.References[index].Phone" />
        </div>
        <button class="btn btn-sm btn-danger" @onclick="() => Wizard.References.RemoveAt(index)">Remove</button>
    </div>
}

<button class="btn btn-outline-secondary mb-3" @onclick="AddReference">+ Add Reference</button>

